/* Ethernet MAC Driver - eth_mac.h */
#ifndef ETH_MAC_H
#define ETH_MAC_H

#include <stdint.h>

typedef struct {
    uint8_t  mac_addr[6];
    uint32_t rx_buf_size;
    uint32_t tx_buf_size;
    uint8_t  rx_buf_count;
    uint8_t  tx_buf_count;
} ETH_Config_t;

typedef struct {
    uint8_t  *data;
    uint16_t  length;
    uint32_t  timestamp;
} ETH_Frame_t;

int  ETH_Init(ETH_Config_t *cfg);
int  ETH_Transmit(ETH_Frame_t *frame);
int  ETH_Receive(ETH_Frame_t *frame);
void ETH_GetMACAddr(uint8_t *mac);
void ETH_SetMACAddr(const uint8_t *mac);
int  ETH_GetLinkStatus(void);
void ETH_Deinit(void);

#endif /* ETH_MAC_H */

